);    return (DefaultPassConfig) passes;  }  public SymbolTable buildKnownSymbolTable() {    SymbolTable symbolTable = new SymbolTable(getTypeRegistry());    MemoizedScopeCreator typedScopeCreator = getTypedScopeCreator();    if (typedScopeCreator != null) {      symbolTable.addScopes(typedScopeCreator.getAllMemoizedScopes());      symbolTable.addSymbolsFrom(typedScopeCreator);    } else {      symbolTable.findScopes(this, externsRoot, jsRoot);    }    GlobalNamespace globalNamespace =        ensureDefaultPassConfig().getGlobalNamespace();    if (globalNamespace != null) {      symbolTable.addSymbolsFrom(globalNamespace);    }    ReferenceCollectingCallback refCollector =        new ReferenceCollectingCallback(            this, ReferenceCollectingCallback.DO_NOTHING_BEHAVIOR);    NodeTraversal.traverse(this, getRoot(), refCollector);    symbolTable.addSymbolsFrom(refCollector);    PreprocessorSymbolTable preprocessorSymbolTable =        ensureDefaultPassConfig().getPreprocessorSymbolTable();    if (preprocessorSymbolTable != null) {      symbolTable.addSymbolsFrom(preprocessorSymbolTable);    }    symbolTable.fillNamespaceReferences();    symbolTable.fillPropertyScopes();    symbolTable.fillThisReferences(this, externsRoot, jsRoot);    symbolTable.fillPropertySymbols(this, externsRoot, jsRoot);    symbolTable.fillJSDocInfo(this, externsRoot, jsRoot);    return symbolTable;  }  @Override  public Scope getTopScope() {    return getPassConfig().getTopScope();  }  @Override  public ReverseAbstractInterpreter getReverseAbstractInterpreter() {    if (abstractInterpreter == null) {      ChainableReverseAbstractInterpreter interpreter =          new SemanticReverseAbstractInterpreter(              getCodingConvention(), getTypeRegistry());      if (options.closurePass) {        interpreter = new ClosureReverseAbstractInterpreter(            getCodingConvention(), getTypeRegistry())            .append(interpreter).getFirst();      }      abstractInterpreter = interpreter;    }    return abstractInterpreter;  }  @Override  TypeValidator getTypeValidator() {    if (typeValidator == null) {      typeValidator = new TypeValidator(this);    }    return typeValidator;  }  //------------------------------------------------------------------------  // Parsing  //------------------------------------------------------------------------  /**   * Parses the externs and main inputs.   *   * @return A synthetic root node whose two children are the externs root   *     and the main root   */  Node parseInputs() {    boolean devMode = options.devMode != DevMode.OFF;    // If old roots exist (we are parsing a second time), detach each of the    // individual file parse trees.    if (externsRoot != null) {      externsRoot.detachChildren();    }    if (jsRoot != null) {      jsRoot.detachChildren();    }    // Parse main js sources.    jsRoot = IR.block();    jsRoot.setIsSyntheticBlock(true);    externsRoot = IR.block();    externsRoot.setIsSyntheticBlock(true);    externAndJsRoot = IR.block(externsRoot, jsRoot);    externAndJsRoot.setIsSyntheticBlock(true);    if (options.tracer.isOn()) {      tracker = new PerformanceTracker(jsRoot,          options.tracer == TracerMode.ALL);      addChangeHandler(tracker.getCodeChangeHandler());    }    Tracer tracer = newTracer("parseInputs");    try {      // Parse externs sources.      for (CompilerInput input : externs) {        Node n = input.getAstRoot(this);        if (hasErrors()) {          return null;        }        externsRoot.addChildToBack(n);      }      // Modules inferred in ProcessCommonJS pass.      if (options.transformAMDToCJSModules || options.processCommonJSModules) {        processAMDAndCommonJSModules();      }      // Check if the sources need to be re-ordered.      if (options.dependencyOptions.needsManagement()) {        for (CompilerInput input : inputs) {          input.setCompiler(this);          // Forward-declare all the provided types, so that they          // are not flagged even if they are dropped from the process.          for (String provide : input.getProvides()) {            getTypeRegistry().forwardDeclareType(provide);          }        }        try {          inputs =              (moduleGraph == null ? new JSModuleGraph(modules) : moduleGraph)              .manageDependencies(options.dependencyOptions, inputs);        } catch (CircularDependencyException e) {          report(JSError.make(              JSModule.CIRCULAR_DEPENDENCY_ERROR, e.getMessage()));          // If in IDE mode, we ignore the error and keep going.          if (hasErrors()) {            return null;          }        } catch (MissingProvideException e) {          report(JSError.make(              MISSING_ENTRY_ERROR, e.getMessage()));          // If in IDE mode, we ignore the error and keep going.          if (hasErrors()) {            return null;          }        }      }      // Check if inputs need to be rebuilt from modules.      boolean staleInputs = false;      for (CompilerInput input : inputs) {        Node n = input.getAstRoot(this);        // Inputs can have a null AST during initial parse.        if (n == null) {          continue;        }        if (n.getJSDocInfo() != null) {          JSDocInfo info = n.getJSDocInfo();          if (info.isExterns()) {            // If the input file is explicitly marked as an externs file, then            // assume the programmer made a mistake and throw it into            // the externs pile anyways.            externsRoot.addChildToBack(n);            input.setIsExtern(true);            input.getModule().remove(input);            externs.add(input);            staleInputs = true;          } else if (info.isNoCompile()) {            input.getModule().remove(input);            staleInputs = true;          }        }      }      if (staleInputs) {        fillEmptyModules(modules);        rebuildInputsFromModules();      }      // Build the AST.      for (CompilerInput input : inputs) {        Node n = input.getAstRoot(this);        if (n == null) {          continue;        }        if (devMode) {          runSanityCheck();          if (hasErrors()) {            return null;          }        }        if (options.sourceMapOutputPath != null ||            options.nameReferenceReportPath != null) {          // Annotate the nodes in the tree with information from the          // input file. This information is used to construct the SourceMap.          SourceInformationAnnotator sia =              new SourceInformationAnnotator(                  input.getName(), options.devMode != DevMode.OFF);          NodeTraversal.traverse(this, n, sia);        }        jsRoot.addChildToBack(n);      }      if (hasErrors()) {        return null;      }      return externAndJsRoot;    } finally {      stopTracer(tracer, "parseInputs");    }  }  /**   * Transforms AMD and CJS modules to something closure compiler can   * process and creates JSModules and the corresponding dependency tree   * on the way.   */  private void processAMDAndCommonJSModules() {    Map<String, JSModule> modulesByName = Maps.newLinkedHashMap();    Map<CompilerInput, JSModule> modulesByInput = Maps.newLinkedHashMap();    // TODO(nicksantos): Refactor module dependency resolution to work nicely    // with multiple ways to express dependencies. Directly support JSModules    // that are equivalent to a signal file and which express their deps    // directly in the source.    for (CompilerInput input : inputs) {      input.setCompiler(this);      Node root = input.getAstRoot(this);      if (root == null) {        continue;      }      if (options.transformAMDToCJSModules) {        new TransformAMDToCJSModule(this).process(null, root);      }      if (options.processCommonJSModules) {        ProcessCommonJSModules cjs = new ProcessCommonJSModules(this,            options.commonJSModulePathPrefix);        cjs.process(null, root);        JSModule m = cjs.getModule();        if (m != null) {          modulesByName.put(m.getName(),