nt   * at the beginning of the output.   */  public void toSource(final CodeBuilder cb,                       final int inputSeqNum,                       final Node root) {    runInCompilerThread(new Callable<Void>() {      @Override      public Void call() throws Exception {        if (options.printInputDelimiter) {          if ((cb.getLength() > 0) && !cb.endsWith("\n")) {            cb.append("\n");  // Make sure that the label starts on a new line          }          Preconditions.checkState(root.isScript());          String delimiter = options.inputDelimiter;          String inputName = root.getInputId().getIdName();          String sourceName = root.getSourceFileName();          Preconditions.checkState(sourceName != null);          Preconditions.checkState(!sourceName.isEmpty());          delimiter = delimiter              .replaceAll("%name%", Matcher.quoteReplacement(inputName))              .replaceAll("%num%", String.valueOf(inputSeqNum));          cb.append(delimiter)            .append("\n");        }        if (root.getJSDocInfo() != null &&            root.getJSDocInfo().getLicense() != null) {          cb.append("/*\n")            .append(root.getJSDocInfo().getLicense())            .append("*/\n");        }        // If there is a valid source map, then indicate to it that the current        // root node's mappings are offset by the given string builder buffer.        if (options.sourceMapOutputPath != null) {          sourceMap.setStartingPosition(              cb.getLineIndex(), cb.getColumnIndex());        }        // if LanguageMode is ECMASCRIPT5_STRICT, only print 'use strict'        // for the first input file        String code = toSource(root, sourceMap, inputSeqNum == 0);        if (!code.isEmpty()) {          cb.append(code);          // In order to avoid parse ambiguity when files are concatenated          // together, all files should end in a semi-colon. Do a quick          // heuristic check if there's an obvious semi-colon already there.          int length = code.length();          char lastChar = code.charAt(length - 1);          char secondLastChar = length >= 2 ?              code.charAt(length - 2) : '\0';          boolean hasSemiColon = lastChar == ';' ||              (lastChar == '\n' && secondLastChar == ';');          if (!hasSemiColon) {            cb.append(";");          }        }        return null;      }    });  }  /**   * Generates JavaScript source code for an AST, doesn't generate source   * map info.   */  @Override  String toSource(Node n) {    initCompilerOptionsIfTesting();    return toSource(n, null, true);  }  /**   * Generates JavaScript source code for an AST.   */  private String toSource(Node n, SourceMap sourceMap, boolean firstOutput) {    CodePrinter.Builder builder = new CodePrinter.Builder(n);    builder.setPrettyPrint(options.prettyPrint);    builder.setLineBreak(options.lineBreak);    builder.setSourceMap(sourceMap);    builder.setSourceMapDetailLevel(options.sourceMapDetailLevel);    builder.setTagAsStrict(firstOutput &&        options.getLanguageOut() == LanguageMode.ECMASCRIPT5_STRICT);    builder.setLineLengthThreshold(options.lineLengthThreshold);    Charset charset = options.outputCharset != null ?        Charset.forName(options.outputCharset) : null;    builder.setOutputCharset(charset);    return builder.build();  }  /**   * Stores a buffer of text to which more can be appended.  This is just like a   * StringBuilder except that we also track the number of lines.   */  public static class CodeBuilder {    private final StringBuilder sb = new StringBuilder();    private int lineCount = 0;    private int colCount = 0;    /** Removes all text, but leaves the line count unchanged. */    void reset() {      sb.setLength(0);    }    /** Appends the given string to the text buffer. */    CodeBuilder append(String str) {      sb.append(str);      // Adjust the line and column information for the new text.      int index = -1;      int lastIndex = index;     